CREATE UNIQUE INDEX "bug_fix_attempts_feedback_attempt_number_unique_idx" ON "bug_fix_attempts" USING btree ("feedback_item_id","attempt_number");--> statement-breakpoint
CREATE UNIQUE INDEX "bug_fix_attempts_feedback_active_unique_idx" ON "bug_fix_attempts" USING btree ("feedback_item_id") WHERE "bug_fix_attempts"."status" IN ('analyzing', 'proposed', 'implementing');--> statement-breakpoint
CREATE UNIQUE INDEX "bug_fix_attempts_cluster_active_unique_idx" ON "bug_fix_attempts" USING btree ("cluster_id") WHERE "bug_fix_attempts"."cluster_id" IS NOT NULL AND "bug_fix_attempts"."status" IN ('analyzing', 'proposed', 'implementing');